  (3,'Morbidelle di semolino con funghi ed erba cipollina alla crema di fontina piemontese','Semolina gnocchi with mushrooms, chives and Fontina cheese from Piemonte','Gnocchi à la semoule avec champignons, ciboulette et crème de fontine piémontaise','Griessgnocchi mit Pilzen und Schnittlauch auf Fontina-Käse Creme','pr',true,false,false,false,NULL),
  (4,'Bresaola della Valtellina con rucola, olio di oliva e limone','Grisons air-dried beef with rucola, olive oil and lemon','Viande de Grisons de la Velteline avec roquette, huile d''olive et citron','Veltliner Bündner Fleisch mit Rucola, Olivenöl und Zitrone','se',false,false,false,false,'3 o 4 fette di bresaola, scaglie di grana o moravia su letto di rucola.. Condire o mettere a parte ciotolina olio evo, limone, sale e pepe. (All. 7)'),
  (5,'Tagliatelle fresche alla Bolognese con ragù di carne','Tagliatelle Bolognese with meat sauce','Tagliatelle fraîches à la Bolonaise avec sauce de viande','Frische Tagliatelle auf Bolognese Art mit Fleischragout','pr',false,false,false,false,'saltare fondo (carote sedano, cipolla) burro, olio, carne maiale, carne manzo, vino bianco, insaporire. Solo dopo aggiungere pomodoro e mescolando spesso. Saltare la pasta con il ragù (all. 5 6 8)'),
  (6,'Maccheroni saltati alla crema di gorgonzola e noci di Sorrento','Macaroni with gorgonzola cream and nuts from Sorrento','Maccheroni à la crème de gorgonzola  avec noix de Sorrento','Maccheroni in Gorgonzolacreme mit Walnuss-Stücken aus Sorrento','pr',true,false,false,false,'sciogliere la panna a bagnomaria con tocchetti di Gorgonzola, salatare  la pasta e guarine con le noci tritate all''uscita. (All. 1,7,8)'),
