  (44,'Sogliola di Dover rosolata alla mugnaia con vino bianco e limone','Browned sole from Dover with white wine and lemon','Sole de Dover à la meunière dorée au vin blanc et citron','Seezunge aus Dover "Müllerin Art" mit Weisswein und Zitrone','se',false,false,false,false,NULL),
  (45,'Consommé di manzo con stracciatella d''uovo','Beef consommé with egg','Consommé de boeuf à l''oeuf','Rinderkraftbrühe mit Ei','pr',false,false,false,false,'brodo ristretto di manzo,fatto bollire con  mistura di uovo,parmigiano , prezzemolo tritato e pane grattugiato (freeg). (All. 3,7,9)'),
  (46,'Capretto giovane al forno agli aromi freschi Mediterranei','Oven baked goat with fresch Mediterranean aromatic herbs','Chevreau au four aux aromes Méditerranéennes','Zicklein aus dem Ofen mit Kräutern "Mediterrané"','se',false,false,true,false,'marinare il capretto in vino bianco, verdure e aromi per 8 ore. Scolare e condire con erbette e sale aromatizzato. Infornare a secco con sonda a 68° e camera a 90°. Servire con il suo fondo profumato con trito di erbette fresche e  mirto. (All.12)'),
  (47,'Listelle di vitello saltate al curry indiano con riso pilaw giallo','Sliced veal with curry and rice pilaff','Veau au curry indien avec riz pilaw jaune','Geschmortes Kalbsragout mit indischem Curry und Pilaw-Reis mit Safranfäden','se',false,false,false,false,NULL),
