  (1086,'Trenette con pesce spada affumicato e melanzane','Trenette-pasta with smoked swordfish and aubergines','Trenette-pâtes avec espadon fumé et aubergines','Trenette-Nudeln mit geräuchertem Schwertfisch und Auberginen','pr',false,false,false,false,NULL),
  (1087,'Sedanini gratinati con funghi','Sedanini-pasta "au gratin" with mushrooms','Sedanini-pâtes gratinées aux champignons','Gratinierte Sedanini-Nudeln mit Pilzen','pr',false,false,false,false,NULL),
  (1089,'Pasticcio di lasagne con radicchio rosso','Lasagne timbale with radicchio','Timbale de laasgnes avec chicorée rouge','Lasagne-Bandnudeln aus dem Ofen mit Radicchio','pr',true,false,false,false,'Besciamella: burro, farina, latte caldo, sale noce moscata, a fuoco spento asiago. radicchio brasato con cipolla e vino, ripetere a strati. Spolverare con parmigiano. Forno ventilato  140° per 20’ (All. 1, 3, 7, 9, 12)'),
  (1090,'Conchiglie saltate al pomodoro e baccala''','Conchiglie-pasta sautéed  with tomato and salt cod','Conchiglie-pâtes sautées à la tomate et morue','Sautierte Conchiglie-Nudeln mit Tomatensauce und Stockfisch','pr',false,false,false,false,NULL),
  (1091,'Crema di cipolle bianche al Masala indiano','Cream of white onion with indian masala','Crème d''oignons blancs avec masala indien','Cremesuppe mit weissen Zwiebeln und indischen Masala','pr',false,false,false,false,'60% di cipolle bianche, restante di patata , sale e pepe. Aggiungere la giusta quantita di acqua e masala indiano  fino a cottura desiderata. Frullare. Passare al cinese Servire con crostini di pane tostati e spolveratina di masala. (All.6,8,10,11)'),
  (1092,'Coda di rospo alla Veneziana','Angler Venetian style','Lotte à la Vénitienne','Seeteufel auf Venetianische Art','se',false,false,true,true,'Scottare sulla griglia i filetti di coda di rospo scaloppati, passare in forno con sonda a 65° e camera a 75°. Nappare all''uscita con un emulsione di olio e.v.o., aglio e prezzemolo. (All. 4)'),
  (1093,'Medaglioni di manzo al Cognac','Medaillons of beef with Cognac','Médaillons de boeuf au Cognac','Rindermedaillons mit Cognac','se',false,false,false,false,'Non è una scaloppina ma bensi alta 2 cm. Infarinare i medaglioni e rosolarli da entrambi i latti. Sfumare con brandy. Aggiungere fondo carne, poca panna. Tenere in caldo e servire al comando .'),
  (1094,'Bis di bruschette al pane pugliese e al pane multicereali','Bis of "bruschetta"-toasted bread with vegetable','Bis de "bruschetta"-pain à là végétarienne','Bis von "Bruschetta"-Röstbrot auf vegetarische Art','se',true,false,false,false,'1 fetta di pane casareccio ed 1 di  pane multicereali passati al forno. Entrambi strofinate con aglio, una pomodoro a cubetti conditi origano, olio sale e pepe., altra dadolate di verdure miste. Prima di servire passarle al forno gratinandole con scamorza o mozzarella. (All.1, 7)'),
  (1095,'Tortelli di biete al Martini Dry','Cards ravioli with Martini Dry sauce','Ravioli farcìs avec blettes au Martini Dry','Mangold-Ravioli an Martini Dry','pr',false,false,false,false,NULL),
  (1096,'Tagliatelle saltate alla ligure','Sautéed tagliatelle ligurian style','Tagliatelle sautées à la ligurienne','Sautierte Tagliatelle auf ligurische Art','pr',false,false,false,false,NULL),
  (1097,'Zuppa di verdure con pomodoro fresco','Vegetable soup with fresh tomato','Soupe de légumes à la tomate fraîche','Gemüsesuppe mit frischen Tomaten','pr',false,false,false,false,NULL),
  (1098,'Omelette all''erba cipollina con giardinetto di legumi','Omelette with chive and vegetables','Omelette à la ciboulette et jardin de légumes','Omelette mit Schnittlauchspitzen und verschiedenen Gemüsen',NULL,false,false,false,false,NULL),
  (1099,'Garganelli con prosciutto alla romagnola','Garganelli-pasta with ham "alla romagnola"','Garganelli-pâtes au jambon "alla romagnola"','Garganelli-Nudeln mit Schinken "alla romagnola"','pr',false,false,false,false,NULL),
  (1100,'Minestrone di fagioli alla milanese','Bean soup "alla milanese"','Soupe d''haricots "alla milanese"','Bohnensuppe "alla milanese"','pr',false,false,false,false,'Tagliare a dadini, patate, carote, zucchine, verza, abbondanti fagioli borlotti, cipolla sedano, aglio, lardo tritato fine. Cuocere per 120'' indi aggiungere il riso. Servire con parmigiano e prezzemolo. (All. 9)'),
  (1101,'Maccheroni saltati al gorgonzola dolce','Sautéed macaroni with sweet gorgonzola','Macaroni sautées au gorgonzola doux','Geschwenkte Makkaroni mit süssem Gorgonzola','pr',false,false,false,false,'Prendiamo una pentola ampia e versiamoci tutte le verdure tagliate a pezzetti, tranne i piselli e la verza. Uniamo anche il trito di lardo preparato poco prima e due cucchiai di olio extravergine d''oliva. Copriamo con abbondante acqua (circa 2 l) e portiamo a bollore. Aggiustiamo di sale, abbassiamo la fiamma e lasciamo che il minestrone cuocia lentamente per almeno 2 ore.'),
  (1102,'Lombo di vitello alla frutta secca','Loin of veal with dried fruit','Longe de veau aux fruits secs','Kalbslendenstück mit Mandeln und Walnüssen','se',false,false,false,false,'Trascorso il tempo possiamo aggiungere in pentola anche i piselli sgranati e la verza tagliata a listarelle. Facciamo proseguire la cottura per una decina di minuti e uniamo il riso.'),
  (1103,'Minestra di broccoli e cavolo nero','Soup of broccoli and kale','Soupe de brocolis et chou vert','Brokkoli-Schwarzkohlsuppe','pr',true,false,false,false,NULL)
INSERT INTO public.piatti (id,nome_it,nome_en,nome_fr,nome_de,tipo,vegetariano,vegano,no_lattosio,locale,ricetta) VALUES
  (1104,'Spiedini di carne alla griglia con olio alle noci','Grilled meat-brochettes with walnut oil','Brochettes de viande grillées à l''huile de noix','Fleischspiesschen vom Grill mit Walnussöl','se',false,false,false,false,'Teniamo conto che un buon minestrone alla milanese deve risultare molto denso.'),
  (1105,'Carbonata di vitello al Pinot bianco e finocchio selvatico','Braised beef with white Pinot wine and wild fennel','Charbonnade de veau au Pinot blanc et fenouil sauvage','Schmorbraten vom Kalb an Pinot Weisswein und Wildfenchel','se',false,false,false,false,'Portiamo in tavola il nostro delizioso primo piatto ancora caldo, insaporiamolo a piacere con del parmigiano grattugiato e gustiamolo insieme a delle fette di pane casereccio leggermente tostate.'),
  (1106,'Crespella vegetale integrale e julienne di peperoni','Wohlemeal crêpe with vegetable and pepper julienne','Crêpe végétale complète et julienne de poivrons','Vollkorn Crêpe mit Gemüse und Paprikastreifen',NULL,false,false,false,false,NULL),
  (1107,'Gnocchetti sardi al Taleggio e tartufo','Gnocchetti sardi-pasta with Taleggio cheese and truffles','Gnocchi-pâtes sardes au fromage Taleggio et truffes','Sardische Gnocchetti-Nudeln mit Taleggio Käse und Trüffeln','pr',false,false,false,false,NULL),
