  (1655,'Spiedino di carne e verdure alla contadina','Meat brochette with vegetable contryside style','Brocchettes de viande é légumes à la paysanne','Fleisch Spiesschen mit Gemüse auf Bauern Art','se',false,false,false,false,NULL),
  (1656,'Piatto di formaggi misti con pere, noci e miele','Cheese dish with pears, walnuts and honey','Plat de fromages avec poires, noix et miel','Gemischte Käseplatte mit Birnen, Walnüssen und Honig','se',false,false,false,false,NULL),
  (1657,'Fagottino di vitello "Cordon bleu"','Veal roulades "Cordon bleu"','Paupiettes de veau "Cordon bleu"','Kalbs-Cordon Bleu','se',false,false,false,false,'Farcire fettine di vitello con prosciutto cotto,  mozzarella  distribuendo il contenuto su metà della fetta lasciando i bordi liberi. Richiudere la carne a portafoglio. Passarla prima in uovo sbattuto e poi in pane grattugiato grossamente e poca farina di mais biana.. Assicurarsi che i bordi si sigillino perfettamente. Friggere per 5’ per parte. Asciugare in carta assorbente. (All. 1,3,7)'),
  (1659,'Coda di rospo al vino Bianco dei Colli','Angler-fish in white wine of the Euganean Hills','Lotte de mer au vin blanc des Collines','Seeteufel in Weisswein von den Euganäischen Hügeln','se',false,false,false,false,NULL),
