  (1665,'Insalata di mozzarelline alla napoletana','Little mozzarella salad napolitan style','Salade de petites mozzarellas à la napolitaine','Kirschmozzarellasalat auf napolitanische Art','se',false,false,false,false,NULL),
  (1666,'Filetto di manzo ai funghi trifolati','Fillet of beef with parsley mushrooms','Filet de boeuf aux champignons à la persillade','Rinderfilet mit Pilzen an Knoblauchpetersilie','se',false,false,false,false,NULL),
  (1667,'Spiedini di carne e verdura alla contadina','Meat and vegetable brochettes country style','Brochettes de viande et légumes à la paysanne','Fleisch- und Gemüsespiesschen auf Bauernart','se',false,false,true,false,'Tagliare a quadrotti zucchine, peperoni e cipolle. Tagliare a cubi di 3 cm 300 g  vitello e/o pollo. Marinare il tutto per alcune ore in evo,aglio, origano. Spadellare brevemente la carne al fine di chiudere i pori. Iniziare lo spiedino con il peperone, alternando la verdura alla carne, finire con un pomodorino. Rosolare gli spiedini girandoli spesso, per 10'' con la marinatura. !! carne deve rimanere morbida. Servire non con sughi ma con olio aromatizzato al rosmarino. Xxx'),
  (1669,'Gnocchetti sardi al pomodoro','Gnocchetti sardi pasta with tomato','Gnocchetti sardi à la sauce tomate','Sardische Gnocchetti mit Tomatensauce','pr',false,false,false,false,NULL),
