  (5077,'Vellutata di Cannellini','Cannellini cream','Crème de Cannellini','Cannellini-Creme','pr',true,true,true,false,'30%patate 70%cannellini ,sedano carota cipolla aglio e legare con amidi. Servire con olio al rosmarino. Guarnire con cannellini'),
  (5078,'Vellutata di cipolle','Onion cream','Velouté d''oignon','Zwiebelcreme','pr',true,false,false,false,'70% cipolle, restante di patata. Aggiungere acqua e cuocere fino a cottura desiderata. Frullare passando al cinese. Aggiungere un 10% di panna. Controllare di non sendere sotto ai 65° in questo ultimo passaggio. Servire con gocce di aceto balsamico ridotto  (All. 1,7) RdA'),
