  (5080,'Vellutata di indivia e zenzero','Creamsoup of endive and ginger','Velouté d''endive et gingembre','Endivien- und Ingwercreme','pr',true,true,true,false,'base crema di patate e indivia.sopra  indivia a julienne cruda e zenzero grattugiato.'),
  (5081,'Zuppa di farro e piselli','Spell and pea soup','Soupe d''épeautre et pois','Dinkel-Erbsensuppe','pr',true,true,true,false,'Base di brodo vegetale farro,piselli interi e a crema. (All. 1,9)'),
  (5082,'Zuppa di funghi','Mushroom soup','Soupe aux champignons','Pilzsuppe','pr',true,true,true,false,'Lessare le patate per almeno 20 minuti, soffriggere lo scalogno (abbondate pure) e aglio, aggiungete i funghi. Preparate il brodo vegetale e unitelo ai funghi, facendo bollire il tutto per almeno 15 minuti. Aggiungete le patate e fate cuocere a fuoco dolce per mezz’ora. Servite con funghi spadellati con aglio. ok 18/4/18'),
  (5083,'Zuppa di gamberi e sedano rapa','Shrimp and celeriac soup','Soupe de crevettes et céleri-rave','Garnelen- und Knollenselleriesuppe','pr',false,false,true,false,'base crema di patate, sedano, bisque i crostacei gamberi saltati.'),
  (5084,'Zuppa di radicchio e pollo','Chicken-radicchio soup','Soupe de radicchio et poulet','Radicchio-Hühnersuppe','pr',false,false,true,false,'base crema di patate, brodo di pollo, radicchio brasato. Legare con amidi..servire con pollo a filetti e radicchio crudo a julienne.'),
  (5085,'Zuppa di sedano','Celery soup','Soupe de céleri','Selleriesuppe','pr',false,false,true,false,'fondo di cipolla,orzo sedano rapa a cubetti e speck.'),
  (5086,'Zuppa di Strigoli e Luppolo selvatico','Strigoliand wild hops soup','Soupe de strigoli et houblon sauvage','Strigoli-Wildhopfen-Suppe','pr',true,true,true,false,'crema di patate con bruscandoli e Carletti trifolati.'),
