  (5399,'Fusilli con canestrelli e crema di zucchine','Fusilli-pasta with scallops and cream of courgettes','Fusilli-pâtes avec pétoncles et crème de courgettes','Fusilli-Nudeln mit Kammuscheln und Zucchinicreme','pr',false,false,false,false,NULL),
  (5400,'Garganelli con prosciutto crudo e rucola','Garganelli-pasta with raw ham and rocket','Graganelli-pâtes au jambon cru et roquette','Garganelli-Nudeln mit rohem Schinken und Rucola','pr',false,false,false,false,'per la salsa,julienne di cipolla, prosciutto crudo e panna. Decorare con rucola .(All. 1,7)'),
  (5401,'Petto di faraona bardata con melograno','Guinea fowl breast with pomegranate','Suprême de pintade au grenade','Perlhuhnbrust mit Granatapfel','se',false,false,false,false,'Aprire i petti e creare una tasca. Salare, riempire la tasca di melograno richiuderli e avvolgerli con la pancetta. Sottovuoto e cucinare a ronner a 65° x 120 min. Abbattere. Prima del servizio rigenerare a 75° x 10 min e rosolare  dalla parte della pelle. Servire con melograno saltato con burro e poco sciroppo di granatina.  (All. 7,9,12)'),
  (5402,'Orecchiette con verdure alla pugliese','Orecchiette-pasta Pugliese style','Orecchiette-pâtes à la Pugliese','Orecchiette-Nudeln nach Apulischer Art','pr',true,false,false,false,'Da con 16/10'),
  (5403,'Arrosto di vitello alle castagne e rosmarino del Garden','Roast veal with chestnuts and rosemary','Rôti de veau aux châtaignes et romarin du Garden','Kalbsbraten mit Kastanien und Rosmarin vom Garden','se',false,false,false,false,'condire carne  con sale aromatizzato, inciderla ed inserre rosmarino. Forno con sonda al nucleo a 75° e camera a 90°. Servire con castagne caramellate cotte in sottovuoto su letto di castagne frullate. (All.  12)'),
  (5404,'Nodino di vitello alla griglia al burro e erba cipollina','Grilled veal cutlet with butter and chive','Côtelette de veau grillée avec beurre à la ciboulette','Kalbskotelett vom Grill mit Butter und Schnittlauch','se',false,false,false,false,'Grigliare al momento sale e alla fine adagiare sopra fettina di limone con burro montato all''erba cipollina.'),
  (5405,'Pappardelle ai tre sapori con mascarpone, piselli e gamberetti','Pappardelle-pasta with mascarpone, green peas and shrimps','Pappardelle-pâtes au mascarpone, crevettes et petits pois','Pappardelle-Nudeln auf Erbsen, Mascarpone und Garnelen','pr',false,false,false,false,'Fare una salsa crema e aggiungere 35% di mascarpone. Saltare velocemnte i gamberi con olio aromatizzato all''aglio e sfumarli con brandy e poco sale. Cucinare i piselli con olio e sale. Unire alla salsa crema e mettere in bagno maria.'),
  (5406,'Emincé di manzo ai peperoni','Beef emincé with peppers','Emincé de bœuf aux poivrons','Rindfleisch-Emincé mit Paprikaschoten','se',false,false,false,false,'Straccetti di manzo infarinati, saltati in padella ,senape e crema di latte. A metà cottura sfumare con vino bianco, aggiungere  peperoni trifolati e completare cottura. Aggiustare di gusto. (All.1, 7,12)'),
  (5407,'Filetto di pesce persico in panure di verdure','Perch fish  in vegetables breadcrumps','Filet de perche  en panure de légumes','Barschfilet in Gemüse-Panade','se',false,false,false,false,NULL),
  (5408,'Crostino autunnale con radicchio e scamorza','Croûton of bread automnal style with Scamorza cheese and radicchio','Croûton de pain à la automnal avec fromage Scamorza et chicorée rouge','Herbst-Röstbrot mit Scamorza Käse und Radicchio',NULL,true,false,false,false,NULL),
