  (5416,'Pennette al taleggio e noci','Pennette-pasta with taleggio cheese and walnuts','Pennette-pâtes avec fromage Taleggio et noix','Pennette-Nudeln mit Taleggio Käse und Walnüssen','pr',true,false,false,false,'Fonduta di taleggio con panna. Aggiungere noci trite alla fine.'),
  (5417,'Fusilli con finferli e pancetta','Fusilli-pasta with chanterelle and bacon','Pennette-pâtes aux chanterelles et bacon','Pennette-Nudeln mit Pfifferlingen und Bacon','pr',false,false,false,false,'Fondo olio aglio e poca cipolla e finferli. Sfumare con con poco vino bianco. Aggiungere la pancetta precedentemente saltata in olio e la salsa crema.'),
