  (5516,'Risotto mantecato al Prosecco e mirtilli neri','Risotto with Prosecco and blueberries','Risotto au Prosecco et aux myrtilles','Risotto mit Prosecco und Heidelbeeren','pr',true,false,false,false,'Tostare il riso a secco. Sfumare con prosecco, fare evaporare e aggiungere brodo. Verso fine cottura aggiungere i mirtilli surgelati. Aggiustare di sale. Quando al dente mantecare con burro e grana'),
  (5517,'Insalata di lenticchie e avocado con germogli di soia e pomodoro','Lentils salad with avocado, soy sprouts and tomatoes','Salade de lentilles avec avocat, germes de soja et tomates','Linsensalat mit Avocado, Sojasprossen und Tomaten',NULL,true,true,true,false,'bollire le lenticchie per 20'' in acqua salata. Quando fredde  condire con olio EVO, salare, aggiungere avocado, germogli di soia, dadolini di pomodoro e basilico. (All.6)'),
